form.script:
(function(){
  // ── helpers ───────────────────────────────────────────
  function safeRules(){
    var el = document.getElementById("sfb-rules-json");
    if(!el) return [];
    try { return JSON.parse((el.textContent||"[]").trim()||"[]") || []; }
    catch(e){ return []; }
  }

  // All input/select/textarea elements for a field id
  function inputNodes(fid){
    return document.querySelectorAll(
      '[data-field-id="'+fid+'"]'
    );
  }

  // Wrapper div (.sfb-field) for a field id
  function wrap(fid){
    return document.querySelector('.sfb-field[data-field-id="'+fid+'"]');
  }

  // Current value(s) of a field — returns string or array
  function valueOf(fid){
    var nodes = inputNodes(fid);
    if(!nodes.length) return "";
    var first = nodes[0];
    var tag   = first.tagName.toLowerCase();

    if(tag === "select"){
      // Return BOTH the value AND the visible label so rules
      // written against either (ID or display text) work
      var selVal   = first.value || "";
      var selLabel = first.options && first.selectedIndex >= 0
        ? (first.options[first.selectedIndex].text || "").trim()
        : "";
      return [selVal, selLabel].filter(function(x){ return x !== ""; });
    }

    if(first.type === "radio"){
      for(var i=0;i<nodes.length;i++){
        if(nodes[i].checked) return nodes[i].value || "";
      }
      return "";
    }

    if(first.type === "checkbox"){
      var checked = [];
      for(var j=0;j<nodes.length;j++){
        if(nodes[j].checked) checked.push(nodes[j].value || "true");
      }
      return checked;
    }

    return first.value || "";
  }

  // Clear all inputs inside a wrapper div
  function clearField(tw){
    tw.querySelectorAll("input,select,textarea").forEach(function(el){
      if(el.type === "checkbox" || el.type === "radio"){
        el.checked = false;
      } else {
        el.value = "";
      }
    });
  }

  // Set required attribute on inputs inside wrapper
  function setRequired(tw, required){
    tw.querySelectorAll("input,select,textarea").forEach(function(el){
      if(required){
        el.setAttribute("required","required");
      } else {
        el.removeAttribute("required");
      }
    });
  }

  function num(x){
    var n = parseFloat(String(x).replace(",",""));
    return isNaN(n) ? NaN : n;
  }

  // Compare trigger value against rule value using operator
  // left = string | string[] (from valueOf)
  // right = rule.value string
  function compare(op, left, right){
    var r = (right == null ? "" : String(right)).trim();

    // Normalise left to array of strings
    var vals = Array.isArray(left)
      ? left.map(function(x){ return String(x||""); })
      : [String(left||"")];

    // Numeric operators
    if(op===">"||op===">="||op==="<"||op==="<="){
      var ln = Array.isArray(left) ? NaN : num(left);
      var rn = num(r);
      if(isNaN(ln)||isNaN(rn)) return false;
      if(op===">")  return ln > rn;
      if(op===">=") return ln >= rn;
      if(op==="<")  return ln < rn;
      if(op==="<=") return ln <= rn;
    }

    var want   = r.toLowerCase();
    var valsL  = vals.map(function(v){ return v.toLowerCase(); });

    if(op==="contains"){
      return valsL.some(function(v){ return v.indexOf(want) !== -1; });
    }
    if(op==="!="){
      if(!valsL.length) return want !== "";
      return valsL.every(function(v){ return v !== want; });
    }
    if(op==="in"||op==="not in"){
      var wanted = want.split(",").map(function(s){ return s.trim(); }).filter(Boolean);
      var ok = valsL.some(function(v){ return wanted.indexOf(v) !== -1; });
      return op==="in" ? ok : !ok;
    }
    // default "="
    if(want === "" && !valsL.filter(function(v){return v!=="";}).length) return true;
    return valsL.some(function(v){ return v === want; });
  }

  // ── init ──────────────────────────────────────────────
  var rules = safeRules();
  if(!rules.length) return;

  // Store original required state of every field
  // so unrequire can restore it correctly
  var originalRequired = {};
  document.querySelectorAll(".sfb-field").forEach(function(tw){
    var fid = tw.getAttribute("data-field-id");
    if(!fid) return;
    var inputs = tw.querySelectorAll("input,select,textarea");
    originalRequired[fid] = false;
    inputs.forEach(function(el){
      if(el.hasAttribute("required")) originalRequired[fid] = true;
    });
  });

  // Collect which fields are ONLY referenced by "show" rules
  // (and never by a "hide" rule) — hide these by default
  var showOnlyTargets = {};
  var hideTargets     = {};
  rules.forEach(function(r){
    if(r.action === "show") showOnlyTargets[String(r.target)] = true;
    if(r.action === "hide") hideTargets[String(r.target)]     = true;
  });
  Object.keys(showOnlyTargets).forEach(function(tid){
    if(!hideTargets[tid]){   // only hide-by-default if no "hide" rule also targets it
      var w = wrap(tid);
      if(w) w.style.display = "none";
    }
  });

  // ── apply: re-evaluate all rules ─────────────────────
  function apply(){
    // Group rules by target so we can resolve conflicts
    // (show wins over hide; last matching action wins within same type)
    var targetState = {};  // fid -> {display, required}

    rules.forEach(function(r){
      var trig = String(r.trigger);
      var targ = String(r.target);
      var ok   = compare(r.op, valueOf(trig), r.value);

      if(!targetState[targ]){
        targetState[targ] = { display: null, required: null };
      }
      var st = targetState[targ];

      if(r.action === "show"){
        // show rule matched → visible; not matched → hidden
        // Only set if no previous show/hide decision, or override
        if(st.display === null || st.display === "hide"){
          st.display = ok ? "show" : "hide";
        } else if(ok){
          st.display = "show";   // show always wins
        }
      } else if(r.action === "hide"){
        if(ok){
          st.display = "hide";   // explicit hide when matched
        } else if(st.display === null){
          st.display = "show";   // condition not met → keep visible
        }
      } else if(r.action === "require"){
        if(ok) st.required = true;
      } else if(r.action === "unrequire"){
        if(ok) st.required = false;
      }
    });

    // Apply resolved states
    Object.keys(targetState).forEach(function(targ){
      var st = targetState[targ];
      var tw = wrap(targ);
      if(!tw) return;

      // Visibility
      if(st.display === "show"){
        tw.style.display = "";
      } else if(st.display === "hide"){
        tw.style.display = "none";
        clearField(tw);   // clear hidden field values
      }

      // Required
      if(st.required === true){
        setRequired(tw, true);
      } else if(st.required === false){
        setRequired(tw, false);
      } else {
        // No require/unrequire rule matched — restore original
        setRequired(tw, originalRequired[targ] || false);
      }
    });
  }

  var formEl = document.getElementById("smart-form");
  if(!formEl) return;

  apply();   // run once on page load

  var debounce = null;
  function onChange(){
    if(debounce) clearTimeout(debounce);
    debounce = setTimeout(apply, 40);
  }
  formEl.addEventListener("input",  onChange, true);
  formEl.addEventListener("change", onChange, true);
})();

(function(){
  function collectAnswers(){
    var out={};
    var nodes=document.querySelectorAll('input[data-field-id],select[data-field-id],textarea[data-field-id]');
    nodes.forEach(function(el){
      var fid=el.getAttribute('data-field-id');
      if(!fid) return;

      if(el.tagName==="SELECT"){
        var label="";
        try{ label = el.options[el.selectedIndex] ? el.options[el.selectedIndex].text : ""; }catch(e){}
        out[fid] = {value:(el.value||""), label:(label||"")};
        return;
      }

      if(el.type==="radio"){
        if(el.checked) out[fid]=el.value||"";
        return;
      }
      if(el.type==="checkbox"){
        if(!out[fid]) out[fid]=[];
        if(el.checked) out[fid].push(el.value||"true");
        return;
      }
      out[fid]=el.value||"";
    });
    return out;
  }

  function post(url, payload){
    return fetch(url, {
      method: "POST",
      headers: {"Content-Type":"application/json"},
      body: JSON.stringify(payload||{}),
      credentials: "same-origin"
    }).then(function(r){ return r.ok ? r.json() : null; })
      .catch(function(){ return null; });
  }

  var form=document.getElementById("smart-form");
  if(!form) return;

  form.addEventListener("submit", function(e){
    var tokenEl=document.querySelector('input[name="token"]');
    var token=tokenEl ? tokenEl.value : "";
    if(!token) return;

    e.preventDefault();

    post("/smart_form/branching/"+encodeURIComponent(token), {answers: collectAnswers()})
      .then(function(data){
        if(data && data.success && data.next_token){
          window.location.href="/smart_form/"+data.next_token;
        } else {
          form.submit();
        }
      });
  }, true);
})();
